-- films 테이블 — films.json 의 supabase 화
-- public 은 SELECT 만, editor 만 INSERT/UPDATE/DELETE 가능

create table if not exists public.films (
  slug                  text primary key,
  tier                  text not null default 'library' check (tier in ('library','featured')),
  brand                 text not null default '',
  name                  text not null default '',
  display_name          text,
  aliases               jsonb not null default '[]'::jsonb,
  description           text,
  iso                   text,
  type                  text,
  format                text,
  issue                 text,
  photographers         jsonb not null default '[]'::jsonb,
  photos                jsonb not null default '[]'::jsonb,
  box_thumbnail         text,
  box_thumbnail_status  text default 'pending',
  can_thumbnail         text,
  can_thumbnail_status  text default 'pending',
  sort_order            int,
  created_at            timestamptz not null default now(),
  updated_at            timestamptz not null default now()
);

create index if not exists films_brand_idx on public.films (brand);
create index if not exists films_tier_idx  on public.films (tier);

-- updated_at 자동 갱신
create or replace function public._films_touch_updated_at()
returns trigger language plpgsql as $$
begin new.updated_at := now(); return new; end $$;

drop trigger if exists films_touch_updated_at on public.films;
create trigger films_touch_updated_at
  before update on public.films
  for each row execute function public._films_touch_updated_at();

alter table public.films enable row level security;

-- 공개 read
drop policy if exists "films_public_select" on public.films;
create policy "films_public_select"
  on public.films for select
  using (true);

-- editor 만 INSERT
drop policy if exists "films_editor_insert" on public.films;
create policy "films_editor_insert"
  on public.films for insert
  to authenticated
  with check (
    exists (select 1 from public.profiles
            where user_id = auth.uid() and is_editor = true)
  );

-- editor 만 UPDATE
drop policy if exists "films_editor_update" on public.films;
create policy "films_editor_update"
  on public.films for update
  to authenticated
  using (
    exists (select 1 from public.profiles
            where user_id = auth.uid() and is_editor = true)
  )
  with check (
    exists (select 1 from public.profiles
            where user_id = auth.uid() and is_editor = true)
  );

-- editor 만 DELETE
drop policy if exists "films_editor_delete" on public.films;
create policy "films_editor_delete"
  on public.films for delete
  to authenticated
  using (
    exists (select 1 from public.profiles
            where user_id = auth.uid() and is_editor = true)
  );

